export const RUMORS: readonly RumorDef[] = BASE_RUMORS.map(rumor => {
  const lead = RUMOR_LEAD_OVERRIDES[rumor.id];
  return lead && !rumor.lead ? { ...rumor, lead } : rumor;
});
